export interface Bundle {
  schemaVersion: string
  purl: string
  profile: Profile
  declarationSchema?: DeclarationSchema | undefined
  source?: SourceInfo | undefined
  metadata?: BundleMetadata | undefined
  checksums: BundleChecksum[]
  declarations: Declaration[]
  symbols: Symbol[]
  softwareComponents: SoftwareComponent[]
  sbomSpdxJson: string
}

export function parseBundle(raw: unknown): Bundle {
  const o = ensureRecord(raw)
  return {
    schemaVersion: typeof o['schemaVersion'] === 'string' ? o['schemaVersion'] : '',
    purl: typeof o['purl'] === 'string' ? o['purl'] : '',
    profile: typeof o['profile'] === 'string' ? (o['profile'] as Profile) : (profileValues ? Object.keys(profileValues)[0] : undefined) as Profile,
    declarationSchema: o['declarationSchema'] !== undefined ? isRecord(o['declarationSchema']) ? parseDeclarationSchema(o['declarationSchema']) : parseDeclarationSchema({}) : undefined,
    source: o['source'] !== undefined ? isRecord(o['source']) ? parseSourceInfo(o['source']) : parseSourceInfo({}) : undefined,
    metadata: o['metadata'] !== undefined ? isRecord(o['metadata']) ? parseBundleMetadata(o['metadata']) : parseBundleMetadata({}) : undefined,
    checksums: Array.isArray(o['checksums']) ? (o['checksums'] as unknown[]).map((item) => isRecord(item) ? parseBundleChecksum(item) : undefined).filter((item): item is BundleChecksum => item !== undefined) : [],
    declarations: Array.isArray(o['declarations']) ? (o['declarations'] as unknown[]).map((item) => isRecord(item) ? parseDeclaration(item) : undefined).filter((item): item is Declaration => item !== undefined) : [],
    symbols: Array.isArray(o['symbols']) ? (o['symbols'] as unknown[]).map((item) => isRecord(item) ? parseSymbol(item) : undefined).filter((item): item is Symbol => item !== undefined) : [],
    softwareComponents: Array.isArray(o['softwareComponents']) ? (o['softwareComponents'] as unknown[]).map((item) => isRecord(item) ? parseSoftwareComponent(item) : undefined).filter((item): item is SoftwareComponent => item !== undefined) : [],
    sbomSpdxJson: typeof o['sbomSpdxJson'] === 'string' ? o['sbomSpdxJson'] : '',
  }
}

export function serializeBundle(value: Bundle): Record<string, unknown> {
  const out: Record<string, unknown> = {}
  out['schemaVersion'] = value.schemaVersion
  out['purl'] = value.purl
  out['profile'] = value.profile
  if (value.declarationSchema !== undefined) {
    out['declarationSchema'] = serializeDeclarationSchema(value.declarationSchema)
  }
  if (value.source !== undefined) {
    out['source'] = serializeSourceInfo(value.source)
  }
  if (value.metadata !== undefined) {
    out['metadata'] = serializeBundleMetadata(value.metadata)
  }
  out['checksums'] = value.checksums.map((item) => serializeBundleChecksum(item))
  out['declarations'] = value.declarations.map((item) => serializeDeclaration(item))
  out['symbols'] = value.symbols.map((item) => serializeSymbol(item))
  out['softwareComponents'] = value.softwareComponents.map((item) => serializeSoftwareComponent(item))
  out['sbomSpdxJson'] = value.sbomSpdxJson
  return out
}


